import { readFileSync, writeFileSync } from 'node:fs'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'

const root = dirname(fileURLToPath(new URL('../package.json', import.meta.url)))

const LEGACY_ASSET_VERSION = '20260511-fa-fonts'

const rewriteCssAssetUrls = (content) =>
  content.replace(/url\((['"]?)\.\.\/fonts\/([^)'"]+)\1\)/g, (_match, _quote, file) =>
    `url('/assets/fonts/${file}?v=${LEGACY_ASSET_VERSION}')`
  )

const cssFiles = [
  'public/assets/css/bootstrap.css',
  'public/assets/css/swiper-bundle.css',
  'public/assets/css/magnific-popup.css',
  'public/assets/css/font-awesome-pro.css',
  'public/assets/css/spacing.css',
  'public/assets/css/atropos.min.css',
  'public/assets/css/main.css'
]


const reinitJsFiles = [
  'public/assets/js/hover-effect.umd.js',
  'public/assets/js/slider-init.js',
  'public/assets/js/main.js',
  'public/assets/js/tp-cursor.js'
]

const jsFiles = [
  'public/assets/js/vendor/jquery.js',
  'public/assets/js/bootstrap-bundle.js',
  'public/assets/js/plugin.js',
  'public/assets/js/three.js',
  'public/assets/js/hover-effect.umd.js',
  'public/assets/js/split-type.js',
  'public/assets/js/swiper-bundle.js',
  'public/assets/js/swiper-gl.js',
  'public/assets/js/effect-slicer.js',
  'public/assets/js/magnific-popup.js',
  'public/assets/js/nice-select.js',
  'public/assets/js/purecounter.js',
  'public/assets/js/isotope-pkgd.js',
  'public/assets/js/imagesloaded-pkgd.js',
  'public/assets/js/atropos.js',
  'public/assets/js/backtop.js',
  'public/assets/js/ajax-form.js',
  'public/assets/js/slider-init.js',
  'public/assets/js/main.js',
  'public/assets/js/tp-cursor.js'
]

const stripSourceMap = (content) =>
  content.replace(/\/\/# sourceMappingURL=.*$/gm, '').replace(/\/\*# sourceMappingURL=.*?\*\//gm, '')

const prepareContent = (content, type) => {
  const stripped = stripSourceMap(content)
  return type === 'css' ? rewriteCssAssetUrls(stripped) : stripped
}

const buildBundle = (files, outFile, type) => {
  const banner = `/* Auto-generated by scripts/build-legacy-assets.mjs. Do not edit this bundle directly. */\n`
  const body = files.map((file) => {
    const fullPath = join(root, file)
    const content = prepareContent(readFileSync(fullPath, 'utf8'), type).trimEnd()
    return `${type === 'css' ? '/*' : '/*'} ${file} */\n${content}\n`
  }).join(type === 'css' ? '\n' : '\n;\n')

  writeFileSync(join(root, outFile), `${banner}${body}\n`)
}

buildBundle(cssFiles, 'public/assets/css/legacy-styles.bundle.css', 'css')
buildBundle(jsFiles, 'public/assets/js/legacy-vendor.bundle.js', 'js')
buildBundle(reinitJsFiles, 'public/assets/js/legacy-reinit.bundle.js', 'js')

console.log('Built legacy CSS and JS bundles.')
